const incoming = items[0]?.json ?? {};
const hasIncomingPayload = Object.keys(incoming).length > 0 && Object.keys(incoming).some((key) => key !== 'executionMode');
const payload = incoming.payload ?? incoming.body ?? incoming ?? {};
const executionId = 'exec-' + Date.now();
const traceId = payload.trace_id || 'trace-missing';
const caseId = payload.case_id || 'case-missing';
return [{ json: { payload, workflow_context: { workflow_mode: 'production_ready', environment: 'production', source: hasIncomingPayload ? 'incoming_payload' : 'empty_payload', generated_at: new Date().toISOString(), workflow_name: 'SOC-Octopus-Agent - Evento Firewall Production', workflow_version: '1.0.0', observability: { started_at_ms: Date.now(), execution_id: executionId, correlation_id: [caseId, traceId].join(':'), trace_id: traceId }, auth_placeholders: { x_api_key: incoming.headers?.['x-api-key'] ?? '{{X-API-Key}}', authorization_bearer: incoming.headers?.authorization ?? '{{Authorization Bearer}}', hmac_signature: incoming.headers?.['x-hmac-signature'] ?? '{{HMAC Signature}}' } }, security_controls: { external_calls_allowed: false, remediation_allowed: false, credentials_allowed: false, production_allowed: false, production_changes_allowed: false, human_approval_required: true } } }];

function asText(value) {
  if (value === undefined || value === null) return '';
  return String(value).trim();
}

function asBool(value) {
  return value === true || value === 'true';
}

function parseEntities(payload) {
  if (payload.entities && typeof payload.entities === 'object' && !Array.isArray(payload.entities)) return payload.entities;
  const summary = asText(payload.entities_summary);
  const result = {};
  for (const part of summary.split(';')) {
    const [key, ...rest] = part.split('=');
    if (key && rest.length) result[key.trim()] = rest.join('=').trim();
  }
  return result;
}

function normalizeEvidence(payload) {
  if (Array.isArray(payload.evidence)) return payload.evidence.map(asText).filter(Boolean);
  const evidence = asText(payload.evidence_summary || payload.evidence);
  return evidence ? [evidence] : [];
}

return items.map((item) => {
  const payload = item.json.payload ?? {};
  const entities = parseEntities(payload);
  const normalized = {
    case_id: asText(payload.case_id),
    trace_id: asText(payload.trace_id),
    input_type: asText(payload.input_type).toLowerCase(),
    source_system: asText(payload.source_system),
    received_at: asText(payload.received_at),
    severity: asText(payload.severity).toLowerCase(),
    title: asText(payload.title),
    description: asText(payload.description),
    classification_hint: asText(payload.classification_hint).toLowerCase(),
    entities,
    evidence: normalizeEvidence(payload),
    firewall_context: {
      user: asText(payload.user || entities.user),
      device: asText(payload.device || entities.device),
      source_ip: asText(payload.source_ip || entities.source_ip),
      destination_ip: asText(payload.destination_ip || entities.destination_ip),
      service: asText(payload.service || entities.service).toLowerCase(),
      rule_id: asText(payload.rule_id || entities.rule_id),
      change_id: asText(payload.change_id || entities.change_id),
      change_window_status: asText(payload.change_window_status || entities.change_window_status).toLowerCase(),
      action: asText(payload.action || entities.action).toLowerCase()
    },
    flags: {
      synthetic_payload: asBool(payload.synthetic_payload),
      contains_real_customer_data: asBool(payload.contains_real_customer_data),
      contains_credentials: asBool(payload.contains_credentials),
      human_approval_required_for_action: asBool(payload.human_approval_required_for_action)
    }
  };

  return {
    json: {
      ...item.json,
      normalized,
      processing_stage: 'normalization',
      normalization_status: 'completed'
    }
  };
});

const allowedSeverities = new Set(['low', 'medium', 'high', 'critical']);
const requiredFields = ['case_id', 'trace_id', 'input_type', 'severity', 'title', 'description'];
const credentialPattern = /(password|passwd|senha|token|secret|client_secret|authorization|bearer)\s*[:=]/i;

return items.map((item) => {
  const normalized = item.json.normalized ?? {};
  const fw = normalized.firewall_context ?? {};
  const missing_fields = requiredFields.filter((field) => !normalized[field]);
  const invalid_fields = [];
  const security = item.json.security_controls ?? {};
  const flags = normalized.flags ?? {};
  const security_violations = [];

  if (normalized.input_type && normalized.input_type !== 'event') invalid_fields.push('input_type');
  if (normalized.severity && !allowedSeverities.has(normalized.severity)) invalid_fields.push('severity');
  if (!fw.device) missing_fields.push('entities.device');
  if (!fw.source_ip) missing_fields.push('entities.source_ip');
  if (!fw.destination_ip) missing_fields.push('entities.destination_ip');
  if (!fw.service) missing_fields.push('entities.service');

  const searchablePayload = [
    normalized.title,
    normalized.description,
    ...(Array.isArray(normalized.evidence) ? normalized.evidence : []),
    Object.values(normalized.entities ?? {}).join(' ')
  ].join(' ');

  if (flags.contains_real_customer_data) security_violations.push('contains_real_customer_data');
  if (flags.contains_credentials) security_violations.push('contains_credentials');
  if (credentialPattern.test(searchablePayload)) security_violations.push('credential_like_material_detected');
  if (security.external_calls_allowed) security_violations.push('external_calls_allowed');
  if (security.remediation_allowed) security_violations.push('remediation_allowed');
  if (security.credentials_allowed) security_violations.push('credentials_allowed');
  if (security.production_allowed) security_violations.push('production_allowed');

  const is_valid = missing_fields.length === 0 && invalid_fields.length === 0 && security_violations.length === 0;

  return {
    json: {
      ...item.json,
      processing_stage: 'validation',
      validation: {
        is_valid,
        status: is_valid ? 'valid' : 'invalid',
        required_fields: [...requiredFields, 'entities.device', 'entities.source_ip', 'entities.destination_ip', 'entities.service'],
        missing_fields,
        invalid_fields,
        security_violations,
        validation_notes: is_valid ? 'Evento aceito para producao controlada.' : 'Evento bloqueado antes de classificacao.'
      }
    }
  };
});

return items.map((item) => {
  const normalized = item.json.normalized ?? {};
  const validation = item.json.validation ?? {};
  return {
    json: {
      ...item.json,
      processing_stage: 'controlled_rejection',
      controlled_rejection: {
        rejected: true,
        reason: 'Evento invalido ou violacao de seguranca detectada antes da classificacao.',
        missing_fields: validation.missing_fields ?? [],
        invalid_fields: validation.invalid_fields ?? [],
        security_violations: validation.security_violations ?? [],
        case_id: normalized.case_id || 'not_avaiprodle',
        trace_id: normalized.trace_id || 'not_avaiprodle',
        next_action: 'Corrigir evento em ambiente controlado e reexecutar manualmente.',
        automated_action_executed: false
      }
    }
  };
});

function includesAny(text, terms) {
  return terms.some((term) => text.includes(term));
}

function riskFromSeverity(severity) {
  if (severity === 'critical') return 'critical';
  if (severity === 'high') return 'high';
  if (severity === 'medium') return 'medium';
  return 'low';
}

const routeRules = [
  {
    route: 'network',
    terms: ['network', 'rede', 'firewall', 'fw', 'regra', 'policy', 'porta', 'origem', 'destino', 'trafego', 'conexao']
  },
  {
    route: 'change_management',
    terms: ['change', 'mudanca', 'janela', 'outside_window', 'fora de janela', 'aprovacao', 'change']
  },
  {
    route: 'security_policy',
    terms: ['bloqueio', 'liberacao', 'permit', 'deny', 'allow', 'drop', 'exposure', 'exposicao', 'perimetro']
  },
  {
    route: 'infrastructure',
    terms: ['infra', 'infrastructure', 'device', 'appliance', 'cluster', 'ha', 'interface', 'rota', 'firmware']
  }
];

const specialistsByRoute = {
  network: ['rede_firewall', 'consolidador'],
  change_management: ['mudanca_firewall', 'rede_firewall', 'consolidador'],
  security_policy: ['politica_seguranca', 'rede_firewall', 'consolidador'],
  infrastructure: ['infraestrutura_rede', 'rede_firewall', 'consolidador'],
  unknown: ['triagem_soc', 'consolidador']
};

return items.map((item) => {
  const normalized = item.json.normalized ?? {};
  const fw = normalized.firewall_context ?? {};
  const evidenceText = Array.isArray(normalized.evidence) ? normalized.evidence.join(' ') : '';
  const entitiesText = Object.values(normalized.entities ?? {}).join(' ');
  const corpus = [
    normalized.classification_hint,
    normalized.title,
    normalized.description,
    fw.service,
    fw.rule_id,
    fw.change_id,
    fw.change_window_status,
    fw.action,
    evidenceText,
    entitiesText
  ].join(' ').toLowerCase();

  let probable_root_cause = 'unknown';
  let classification_reason = 'Nenhuma regra local identificou causa provavel com confianca suficiente.';
  let confidence_level = 'low';

  const hint = normalized.classification_hint;
  const directRoute = routeRules.find((rule) => rule.route === hint || (hint === 'firewall' && rule.route === 'network') || (hint === 'network' && rule.route === 'network') || (hint === 'change' && rule.route === 'change_management') || (hint === 'policy' && rule.route === 'security_policy') || (hint === 'infra' && rule.route === 'infrastructure'));
  if (directRoute) {
    probable_root_cause = directRoute.route;
    classification_reason = `classification_hint indicou rota ${directRoute.route}.`;
    confidence_level = 'high';
  } else {
    const matched = routeRules.find((rule) => includesAny(corpus, rule.terms));
    if (matched) {
      probable_root_cause = matched.route;
      classification_reason = `Regras locais identificaram termos associados a ${matched.route}.`;
      confidence_level = 'medium';
    }
  }

  if (fw.change_window_status === 'outside_window' && probable_root_cause === 'network') {
    classification_reason = 'Evento de firewall com alteracao fora de janela planejada; manter foco em rede e mudanca.';
    confidence_level = 'high';
  }

  return {
    json: {
      ...item.json,
      processing_stage: 'classification',
      classification: {
        probable_root_cause,
        routing_key: probable_root_cause,
        risk_level: riskFromSeverity(normalized.severity),
        confidence_level,
        classification_reason,
        false_positive_assessment: 'possible',
        possible_false_positive: true,
        specialists_recommended: specialistsByRoute[probable_root_cause] ?? specialistsByRoute.unknown
      }
    }
  };
});

